async (params, browser) => {
  // Open the tweet
  await browser.open(`${params.tweet_url}`)

  // Wait for page content
  await browser.waitForSelector('article[data-testid=\'tweet\']', 15000)

  // Let page settle
  await browser.wait(1000)

  // Wait for like button
  await browser.waitForSelector('[data-testid$=\'like\']', 10000)

  // Like the tweet (skip if already liked)
  const result = await browser.evaluate(`const likeBtn = document.querySelector('[data-testid$="like"]'); const unlikeBtn = document.querySelector('[data-testid$="unlike"]'); if (unlikeBtn) return { already_liked: true, message: 'Tweet is already liked' }; if (likeBtn) { likeBtn.click(); return { success: true, message: 'Tweet liked' }; } return { success: false, message: 'Like button not found' }`)

  return result
}
